/* Marge interne du header : bas + droite */
header .wp-block-group,
.wp-block-template-part .wp-block-group {
  padding-bottom: 10px !important;
  padding-right: 38px !important;
}

/* Ombre douce sous le header */
header,
.wp-block-template-part {
  box-shadow: 0 8px 24px rgba(11, 31, 58, 0.08) !important;
  position: relative !important;
  z-index: 10 !important;
}
/* Puces rondes Urbizen */
.urbizen-list-check {
  list-style: none;
  padding-left: 0;
  margin-left: 0;
}

.urbizen-list-check li {
  position: relative;
  padding-left: 34px;
  margin-bottom: 12px;
  line-height: 1.5;
}

.urbizen-list-check li::before {
  content: "✓";
  position: absolute;
  left: 0;
  top: 2px;
  width: 20px;
  height: 20px;
  border-radius: 999px;
  background: #F9B233;
  color: #0B1F3A;
  font-weight: 900;
  font-size: 13px;
  line-height: 20px;
  text-align: center;
}

