/* Section Pourquoi choisir Urbizen */
@media (min-width: 782px) {
  .grille-urbizen {
    position: relative;
    margin-top: 45px;
  }

  .grille-urbizen::before {
    content: "";
    position: absolute;
    top: -28px;
    left: 12%;
    right: 12%;
    height: 4px;
    background: #8DE0BF;
    border-radius: 999px;
    z-index: 1;
  }

  .grille-urbizen .carte-urbizen {
    position: relative;
    z-index: 2;
  }

  .grille-urbizen .carte-urbizen::before {
    content: "";
    position: absolute;
    top: -28px;
    left: 50%;
    transform: translateX(-50%);
    width: 4px;
    height: 28px;
    background: #8DE0BF;
    border-radius: 999px;
    z-index: 1;
  }
}

@media (max-width: 781px) {
  .grille-urbizen::before,
  .grille-urbizen .carte-urbizen::before {
    display: none;
  }
}
/* Liste Urbizen avec ronds verts reliés */
.urbizen-timeline-list {
  list-style: none;
  padding-left: 0;
  margin-left: 0;
  position: relative;
}

.urbizen-timeline-list li {
  position: relative;
  padding-left: 34px;
  margin-bottom: 14px;
  color: #334155;
  font-size: 18px;
  line-height: 1.45;
}

/* Ligne verticale */
.urbizen-timeline-list li::before {
  content: "";
  position: absolute;
  left: 8px;
  top: 21px;
  width: 3px;
  height: calc(100% + 14px);
  background: #002D6B;
  opacity: 0.65;
}

/* Rond vert */
.urbizen-timeline-list li::after {
  content: "";
  position: absolute;
  left: 0;
  top: 6px;
  width: 18px;
  height: 18px;
  background: #002D6B;
  border-radius: 50%;
  box-shadow: 0 0 0 2px rgba(123, 220, 181, 0.18);
}

/* Pas de ligne après le dernier élément */
.urbizen-timeline-list li:last-child::before {
  display: none;
}
